// Generated by Claude Opus 4.6

import userEvent from '@testing-library/user-event';
import React from 'react';

import getComponentRenderer, { screen } from '@/services/__mocks__/getComponentRenderer';

import { ResourceLimitsPanel } from '..';

const mockOnMemoryLimitChange = jest.fn();
const mockOnCpuLimitChange = jest.fn();

const { renderComponent } = getComponentRenderer(getComponent);

function getComponent(props?: Partial<React.ComponentProps<typeof ResourceLimitsPanel>>) {
  return (
    <ResourceLimitsPanel
      memoryLimit={props?.memoryLimit ?? 0}
      cpuLimit={props?.cpuLimit ?? 0}
      onMemoryLimitChange={props?.onMemoryLimitChange ?? mockOnMemoryLimitChange}
      onCpuLimitChange={props?.onCpuLimitChange ?? mockOnCpuLimitChange}
    />
  );
}

describe('ResourceLimitsPanel', () => {
  afterEach(() => {
    jest.clearAllMocks();
  });

  test('should render panel with "Additional Options" title', () => {
    renderComponent();

    expect(screen.getByText('Additional Options')).toBeInTheDocument();
  });

  test('should render accordion with "Resource Limits" toggle', () => {
    renderComponent();

    expect(screen.getByRole('button', { name: /Resource Limits/i })).toBeInTheDocument();
  });

  test('should be expanded by default', () => {
    renderComponent();

    const toggle = screen.getByRole('button', { name: /Resource Limits/i });
    expect(toggle).toHaveAttribute('aria-expanded', 'true');
  });

  test('should collapse when toggle is clicked', async () => {
    renderComponent();

    const toggle = screen.getByRole('button', { name: /Resource Limits/i });
    await userEvent.click(toggle);

    expect(toggle).toHaveAttribute('aria-expanded', 'false');
  });

  test('should render MemoryLimitField and CpuLimitField', () => {
    renderComponent();

    expect(screen.getByText(/Memory Limit/i)).toBeInTheDocument();
    expect(screen.getByText(/CPU Limit/i)).toBeInTheDocument();
  });
});
